import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface FeedingSchedule {
  meal: string;
  time: string;
}

interface NextVetAppointment {
  date: string;
  time: string;
  vetName: string;
}

interface ActivityLevel {
  current: string;
  trend: number[];
}

interface PetCareData {
  feedingSchedule: FeedingSchedule[];
  nextVetAppointment: NextVetAppointment;
  activityLevel: ActivityLevel;
}

export default function Widget() {
  const petCareData = response.data as PetCareData;
  const { feedingSchedule, nextVetAppointment, activityLevel } = petCareData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Feeding Schedule
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {feedingSchedule.slice(0, 3).map((schedule, index) => (
                <Chip
                  key={index}
                  label={`${schedule.meal}: ${schedule.time}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Next Vet Appointment
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {nextVetAppointment.date} at {nextVetAppointment.time} with {nextVetAppointment.vetName}
            </Typography>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Activity Level: {activityLevel.current}
            </Typography>
            <LineChart
              height={80}
              series={[
                {
                  data: activityLevel.trend,
                  color: '#FFC107',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: [0, 1, 2, 3, 4, 5, 6], hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
